/bin/bash -lc "python - <<'PY'
import problems

valid_durations = {
    '1h30m15s': 5415, '90m': 5400, '2h': 7200, '45s': 45,
    '1h5s': 3605, '120m': 7200, '0s': 0, '00h00m00s': 0,
}
for value, expected in valid_durations.items():
    assert problems.parse_duration(value) == expected
for value in ['', None, 1, '1', 'h', '30m1h', '1h2h', '-1s', ' 1s', '1s ', '1h"'!'"', '١h']:
    try:
        problems.parse_duration(value)
    except ValueError:
        pass
    else:
        raise AssertionError(('duration accepted', value))

assert problems.luhn_valid('4539 1488 0343 6467')
assert problems.luhn_valid('4539-1488-0343-6467')
assert problems.luhn_valid('0')
for value in ('', '1', '  - ', '12x', '٠', None):
    assert not problems.luhn_valid(value), value

source = {'a': {'b': 1, 'c': {'d': 2}, 'empty': {}}, 'e': [3], '': {'x': 4}}
assert problems.flatten(source) == {'a.b': 1, 'a.c.d': 2, 'e': [3], '.x': 4}
assert source['a']['c'] == {'d': 2}
assert problems.flatten({'a': {'b': 1}}, '/') == {'a/b': 1}
assert problems.top_k_frequent(['b','a','b','c','a'], 2) == ['a','b']
assert problems.top_k_frequent(['a'], 0) == []
assert problems.top_k_frequent(['a'], 5) == ['a']
assert problems.rolling_max([1,3,2,5,4], 3) == [3,5,5]
assert problems.rolling_max([2,1], 1) == [2,1]
assert problems.rolling_max([], 1) == []
assert problems.rolling_max([1], 2) == []
try:
    problems.rolling_max([1], 0)
except ValueError:
    pass
else:
    raise AssertionError('window')
print('checks passed')
PY
python -m py_compile problems.py"

